  1→import type { SearchField, SearchFieldUnit, SearchInstitution, SearchOutputField, Theme } from './types'
  2→
  3→// Field names rendered first in the sidebar, in order. Unknown fields follow alphabetically by label.
  4→export const PREFERRED_ORDER = ['name', 'city', 'state']
  5→
  6→export function sortFields(fields: SearchField[]): SearchField[] {
  7→  return [...fields].sort((a, b) => {
  8→    const ai = PREFERRED_ORDER.indexOf(a.name)
  9→    const bi = PREFERRED_ORDER.indexOf(b.name)
 10→    if (ai !== -1 && bi !== -1) return ai - bi
 11→    if (ai !== -1) return -1
 12→    if (bi !== -1) return 1
 13→    return a.label.localeCompare(b.label)
 14→  })
 15→}
 16→
 17→// Ordered list of themes for sidebar rendering. Only themes with fields are shown.
 18→export const THEME_ORDER: Theme[] = [
 19→  'CORE',
 20→  'LOCATION',
 21→  'ACADEMICS',
 22→  'COST',
 23→  'OUTCOMES',
 24→  'RANKING',
 25→  'ADMISSIONS',
 26→  'ATHLETICS',
 27→  'FIELDS_OF_STUDY',
 28→  'CULTURAL_ENVIRONMENT',
 29→  'WEATHER',
 30→]
 31→
 32→export const THEME_LABELS: Record<Theme, string> = {
 33→  CORE: 'Core',
 34→  LOCATION: 'Location',
 35→  ACADEMICS: 'Academics',
 36→  COST: 'Cost & Financial Aid',
 37→  OUTCOMES: 'Outcomes',
 38→  RANKING: 'Rankings',
 39→  ADMISSIONS: 'Admissions',
 40→  ATHLETICS: 'Athletics',
 41→  FIELDS_OF_STUDY: 'Fields of Study',
 42→  CULTURAL_ENVIRONMENT: 'Cultural Environment',
 43→  WEATHER: 'Weather & Climate',
 44→  PHYSICAL_ENVIRONMENT: 'Physical Environment',
 45→  DEMOGRAPHICS: 'Demographics',
 46→  REPUTATION: 'Reputation',
 47→  SAFETY: 'Safety',
 48→  STUDENT_LIFE: 'Student Life',
 49→  METADATA: 'Metadata',
 50→  OTHER: 'Other',
 51→}
 52→
 53→export interface ThemeGroup {
 54→  theme: Theme
 55→  label: string
 56→  fields: SearchField[]
 57→}
 58→
 59→export function fieldsByTheme(fields: SearchField[]): ThemeGroup[] {
 60→  // Group fields by theme
 61→  const grouped = new Map<Theme, SearchField[]>()
 62→  for (const f of fields) {
 63→    const existing = grouped.get(f.theme)
 64→    if (existing) {
 65→      existing.push(f)
 66→    } else {
 67→      grouped.set(f.theme, [f])
 68→    }
 69→  }
 70→
 71→  // Sort fields within each group alphabetically by label
 72→  for (const group of grouped.values()) {
 73→    group.sort((a, b) => a.label.localeCompare(b.label))
 74→  }
 75→
 76→  // Build ordered result: known themes first, then any unknown themes
 77→  const result: ThemeGroup[] = []
 78→  for (const theme of THEME_ORDER) {
 79→    const group = grouped.get(theme)
 80→    if (group && group.length > 0) {
 81→      result.push({ theme, label: THEME_LABELS[theme], fields: group })
 82→      grouped.delete(theme)
 83→    }
 84→  }
 85→  // Append any remaining themes not in THEME_ORDER
 86→  for (const [theme, group] of grouped) {
 87→    if (group.length > 0) {
 88→      result.push({ theme, label: THEME_LABELS[theme] ?? String(theme), fields: group })
 89→    }
 90→  }
 91→
 92→  return result
 93→}
 94→
 95→const MILES_TO_KM = 1.60934
 96→
 97→export function buildFilterInputs(
 98→  filters: Record<string, unknown>,
 99→): Array<{ field: string; value: unknown }> {
100→  return Object.entries(filters).map(([field, value]) => {
101→    if (
102→      typeof value === 'object' &&
103→      value !== null &&
104→      'latitude' in value &&
105→      'longitude' in value &&
106→      'radiusMiles' in value
107→    ) {
108→      const v = value as { latitude: number; longitude: number; radiusMiles: number }
109→      return {
110→        field,
111→        value: {
112→          kind: 'radius',
113→          radius: { lat: v.latitude, lng: v.longitude, radius_km: v.radiusMiles * MILES_TO_KM },
114→        },
115→      }
116→    }
117→    return { field, value }
118→  })
119→}
120→
121→export function serializeFilterValue(value: unknown): string {
122→  if (typeof value === 'object' && value !== null) {
123→    if ('query' in value) return String((value as { query: string }).query)
124→    if ('value' in value) return String((value as { value: string }).value)
125→    if ('values' in value) return (value as { values: string[] }).values.join(',')
126→    if ('latitude' in value && 'longitude' in value && 'radiusMiles' in value) {
127→      const g = value as { latitude: number; longitude: number; radiusMiles: number }
128→      return `${g.latitude},${g.longitude},${g.radiusMiles}`
129→    }
130→    if ('max' in value && !('min' in value))
131→      return String((value as { max: number }).max)
132→    if ('min' in value && !('max' in value))
133→      return String((value as { min: number }).min)
134→    if ('min' in value && 'max' in value) {
135→      const r = value as { min: number; max: number }
136→      return `${r.min},${r.max}`
137→    }
138→  }
139→  return String(value)
140→}
141→
142→export function parseUrlToFilters(
143→  params: URLSearchParams,
144→  fields: SearchField[],
145→): Record<string, unknown> {
146→  const filters: Record<string, unknown> = {}
147→  const fieldMap = new Map(fields.map((f) => [f.name, f]))
148→
149→  // Handle legacy ?q= param — maps to the "name" field
150→  const q = params.get('q')
151→  if (q && !params.has('name')) {
152→    filters.name = { query: q }
153→  }
154→
155→  for (const [key, raw] of params.entries()) {
156→    if (key === 'q') continue
157→    const field = fieldMap.get(key)
158→    if (!field) continue
159→
160→    if (field.__typename === 'TextSearchField') {
161→      filters[key] = { query: raw }
162→    } else if (field.__typename === 'BinarySearchField') {
163→      filters[key] = { value: raw }
164→    } else if (field.__typename === 'ChoiceSearchField') {
165→      if (field.maxSelections === 1) {
166→        filters[key] = { value: raw }
167→      } else {
168→        filters[key] = { values: raw.split(',').filter(Boolean) }
169→      }
170→    } else if (field.__typename === 'NumericalSearchField') {
171→      const num = Number(raw)
172→      if (!isNaN(num)) {
173→        filters[key] = { value: num }
174→      }
175→    } else if (field.__typename === 'GeoSearchField') {
176→      const parts = raw.split(',')
177→      if (parts.length === 3) {
178→        const [lat, lng, r] = parts.map(Number)
179→        if (!isNaN(lat) && !isNaN(lng) && !isNaN(r)) {
180→          filters[key] = { latitude: lat, longitude: lng, radiusMiles: r }
181→        }
182→      }
183→    } else if (field.__typename === 'NumericalRangeSearchField') {
184→      if (raw.includes(',')) {
185→        const [minStr, maxStr] = raw.split(',')
186→        const minVal = Number(minStr)
187→        const maxVal = Number(maxStr)
188→        if (!isNaN(minVal) && !isNaN(maxVal)) {
189→          filters[key] = { min: minVal, max: maxVal }
190→        }
191→      } else {
192→        const num = Number(raw)
193→        if (!isNaN(num)) {
194→          filters[key] = { max: num }
195→        }
196→      }
197→    }
198→  }
199→
200→  return filters
201→}
202→
203→export interface OutputFieldThemeGroup {
204→  theme: Theme
205→  label: string
206→  fields: SearchOutputField[]
207→}
208→
209→export function outputFieldsByTheme(fields: SearchOutputField[]): OutputFieldThemeGroup[] {
210→  const grouped = new Map<Theme, SearchOutputField[]>()
211→  for (const f of fields) {
212→    const existing = grouped.get(f.theme)
213→    if (existing) {
214→      existing.push(f)
215→    } else {
216→      grouped.set(f.theme, [f])
217→    }
218→  }
219→
220→  const result: OutputFieldThemeGroup[] = []
221→  for (const theme of THEME_ORDER) {
222→    const group = grouped.get(theme)
223→    if (group && group.length > 0) {
224→      result.push({ theme, label: THEME_LABELS[theme], fields: group })
225→      grouped.delete(theme)
226→    }
227→  }
228→  for (const [theme, group] of grouped) {
229→    if (group.length > 0) {
230→      result.push({ theme, label: THEME_LABELS[theme] ?? String(theme), fields: group })
231→    }
232→  }
233→
234→  return result
235→}
236→
237→/**
238→ * Navigates a dot-path (e.g. "academics.enrollment") into a SearchInstitution
239→ * and returns the leaf value. Returns undefined if any segment is missing.
240→ */
241→export function getFieldValue(
242→  inst: SearchInstitution,
243→  outputKey: string | null | undefined,
244→): unknown {
245→  if (!outputKey) return undefined
246→  const parts = outputKey.split('.')
247→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
248→  let current: any = inst
249→  for (const part of parts) {
250→    if (current == null || typeof current !== 'object') return undefined
251→    current = current[part]
252→  }
253→  return current ?? undefined
254→}
255→
256→/**
257→ * Parse a blend URL param like "rank_us_news_national:40,rank_forbes:30" into a record.
258→ */
259→export function parseBlendParam(raw: string | null): Record<string, number> {
260→  if (!raw) return {}
261→  const result: Record<string, number> = {}
262→  for (const pair of raw.split(',')) {
263→    const [field, weightStr] = pair.split(':')
264→    if (field && weightStr) {
265→      const weight = Number(weightStr)
266→      if (!isNaN(weight) && weight > 0) {
267→        result[field] = weight
268→      }
269→    }
270→  }
271→  return result
272→}
273→
274→/**
275→ * Serialize blend weights to a URL param string.
276→ * Only includes non-zero weights.
277→ */
278→export function serializeBlendWeights(weights: Record<string, number>): string {
279→  return Object.entries(weights)
280→    .filter(([, w]) => w > 0)
281→    .map(([field, weight]) => `${field}:${weight}`)
282→    .join(',')
283→}
284→
285→export function formatCellValue(value: unknown, unit?: SearchFieldUnit | null): string {
286→  if (value === null || value === undefined || value === '') return '—'
287→  const num = Number(value)
288→  if (unit === 'DOLLARS' && !isNaN(num)) {
289→    return `$${Math.round(num).toLocaleString()}`
290→  }
291→  if (unit === 'PERCENTAGE' && !isNaN(num)) {
292→    return `${(num * 100).toFixed(1)}%`
293→  }
294→  if (unit === 'MILES' && !isNaN(num)) {
295→    return `${num.toLocaleString()} mi`
296→  }
297→  return String(value)
298→}
